css:
.loader {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
   width: 40px;
   aspect-ratio: 1;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) 50%/8px 8px no-repeat, conic-gradient(from -90deg at 15px 15px,#0000 90deg,currentColor 0) 0 0/25px 25px;
   animation: l7 1s infinite;
}
@keyframes l7  {
  0% {background-position:50%,0 0}
50% {background-position:50%,25px 0}
100% {background-position:50%,25px 25px}
}
